def parse_frequency(frequency):
	"""
	Given a frequency string with a number and a unit of time, return a corresponding
datetime.timedelta instance or None if the frequency is None or "always".

For instance, given "3 weeks", return datetime.timedelta(weeks=3)

Raise ValueError if the given frequency cannot be parsed.
	"""
	if frequency is None or frequency == "always":
		return None

	frequency = frequency.lower()
	if frequency.endswith("days"):
		return timedelta(days=int(frequency[:-5]))
	elif frequency.endswith("hours"):
		return timedelta(hours=int(frequency[:-6]))
	elif frequency.endswith("minutes"):
		return timedelta(minutes=int(frequency[:-7]))
	elif frequency.endswith("seconds"):
		return timedelta(seconds=int(frequency[:-8]))
	elif frequency.endswith("weeks"):
		return timedelta(weeks=int(frequency[:-7]))
	else:
		raise ValueError("Invalid frequency unit")

